import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Services from './pages/Services';
import Registration from './pages/Registration';
import Admin from './pages/Admin'; // नवीन Admin पेज इंपोर्ट करा
import 'bootstrap/dist/css/bootstrap.min.css';

function App() {
  return (
    <Router>
      <div className="App">
        {/* Navbar */}
        <nav className="navbar navbar-expand-lg navbar-dark bg-dark shadow sticky-top">
          <div className="container">
            <Link className="navbar-brand fw-bold fs-3" to="/">Freelance<span className="text-primary">Hub</span></Link>
            <div className="collapse navbar-collapse justify-content-end">
              <ul className="navbar-nav">
                <li className="nav-item"><Link className="nav-link" to="/">Home</Link></li>
                <li className="nav-item"><Link className="nav-link" to="/services">Services</Link></li>
                <li className="nav-item"><Link className="btn btn-primary text-white ms-lg-3" to="/register">Hire Me</Link></li>
              </ul>
            </div>
          </div>
        </nav>

        {/* Routes */}
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/services" element={<Services />} />
          <Route path="/register" element={<Registration />} />
          <Route path="/admin" element={<Admin />} /> {/* Admin Route */}
        </Routes>
      </div>
    </Router>
  );
}

export default App;
